function setting(PDO $p,string $k,$default){$s=$p->prepare('SELECT setting_value FROM system_settings WHERE setting_key=?');$s->execute([$k]);$v=$s->fetchColumn();if($v===false)return $default;$j=json_decode($v,true);return json_last_error()===JSON_ERROR_NONE?$j:$v;}
if(!$login&&isset($_POST['save_settings'])){$data=['ranks'=>['low'=>isset($_POST['rank_low']),'high'=>isset($_POST['rank_high'])],'close_date'=>trim((string)($_POST['close_date']??'29/12/1447')),'weights'=>[],'enabled'=>[],'texts'=>[]];foreach(['low','high'] as $r)foreach(['performance','training','third','exam'] as $e){$data['weights'][$r][$e]=(float)($_POST['w_'.$r.'_'.$e]??0);$data['enabled'][$r][$e]=isset($_POST['e_'.$r.'_'.$e]);}foreach(['page_title','basic_title','basic_note','rank_label','rank_low','rank_high','close_date_label','rank_date_label','comparison_title','comparison_note','performance_label','performance_hint','training_title','add_training','low_title','proposal_label','execution_label','volunteer_title','add_volunteer','high_title','interview_label','exam_title','exam_label','calculate_button','new_calculation','tie_title','tie_note','tie_items'] as $k)$data['texts'][$k]=trim((string)($_POST['t_'.$k]??''));$q=$pdo->prepare('INSERT INTO system_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($data as $k=>$v)$q->execute([$k,json_encode($v,JSON_UNESCAPED_UNICODE)]);$saved=true;}
if(!$login){$ranks=setting($pdo,'ranks',['low'=>true,'high'=>true]);$closeDate=setting($pdo,'close_date','29/12/1447');$weights=setting($pdo,'weights',['low'=>['performance'=>30,'training'=>30,'third'=>30,'exam'=>10],'high'=>['performance'=>30,'training'=>30,'third'=>30,'exam'=>10]]);$enabled=setting($pdo,'enabled',['low'=>['performance'=>true,'training'=>true,'third'=>true,'exam'=>true],'high'=>['performance'=>true,'training'=>true,'third'=>true,'exam'=>true]]);$texts=setting($pdo,'texts',[]);$stats=$pdo->query("SELECT (SELECT COUNT(*) FROM visitors) visitors,(SELECT COALESCE(SUM(return_count),0) FROM visitors) returns,(SELECT COUNT(*) FROM visitor_events WHERE event_type='search') searches,(SELECT COUNT(*) FROM visitor_events) events")->fetch();$visitors=$pdo->query('SELECT visitor_code,created_at,updated_at,return_count,calculator_data FROM visitors ORDER BY updated_at DESC LIMIT 200')->fetchAll();}
