>'إيضاح تقييم الأداء','training_title'=>'عنوان التدريب','add_training'=>'زر إضافة برنامج تدريبي','low_title'=>'عنوان المبادرات والتطوع','proposal_label'=>'عنوان نسبة المقترح','execution_label'=>'عنوان نسبة التنفيذ','volunteer_title'=>'عنوان سجل التطوع','add_volunteer'=>'زر إضافة تطوع','high_title'=>'عنوان المقابلة الشخصية','interview_label'=>'عنوان درجة المقابلة','exam_title'=>'عنوان الاختبار','exam_label'=>'عنوان نتيجة الاختبار','calculate_button'=>'نص زر الاحتساب','new_calculation'=>'نص زر احتساب جديد','tie_title'=>'عنوان عناصر الترجيح','tie_note'=>'إيضاح عناصر الترجيح','tie_items'=>'بنود عناصر الترجيح'];
?><!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>لوحة مالك النظام</title><style>body{font-family:Tahoma;background:#f4f8f7;color:#102a43;margin:0;padding:18px}.box{max-width:1150px;margin:auto}.card{background:#fff;border-radius:18px;padding:20px;margin:14px 0;box-shadow:0 8px 30px #0001}.tabs{display:flex;gap:8px;position:sticky;top:0;background:#f4f8f7;padding:8px 0;z-index:2}.tabs a,button{padding:11px 16px;border:0;border-radius:10px;background:#0b6b62;color:#fff;text-decoration:none;font:inherit}input,textarea{width:100%;padding:10px;border:1px solid #ccd;border-radius:9px;font:inherit;box-sizing:border-box}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.weights{overflow:auto}table{width:100%;border-collapse:collapse}th,td{padding:9px;border-bottom:1px solid #ddd;text-align:right}.stat{font-size:28px;font-weight:bold}.checks label{display:block;margin:8px 0}input[type=checkbox]{width:auto}@media(max-width:700px){.grid{grid-template-columns:1fr}}</style></head><body><main class="box">
