<?php else:?><form method="post" style="float:left"><button name="logout">خروج</button></form><h1>لوحة مالك النظام</h1><nav class="tabs"><a href="#admin">الإدارة</a><a href="#appearance">المظهر</a><a href="#activity">النشاط</a></nav><?php if(isset($saved)):?><div class="card" style="color:#087f5b">تم حفظ الإعدادات.</div><?php endif?><form method="post"><input type="hidden" name="save_settings" value="1">
<section class="card" id="admin"><h2>الإدارة</h2><div class="grid checks"><div><h3>أنواع المراتب</h3><label><input type="checkbox" name="rank_low" <?=!empty($ranks['low'])?'checked':''?>> العاشرة فما دون</label><label><input type="checkbox" name="rank_high" <?=!empty($ranks['high'])?'checked':''?>> الحادية عشرة وأعلى</label></div><div><h3>التاريخ الافتراضي</h3><label>تاريخ إغلاق محضر الترقيات</label><input name="close_date" value="<?=htmlspecialchars((string)$closeDate)?>" placeholder="29/12/1447"></div></div><h3>الأوزان وتفعيل العناصر</h3><div class="weights"><table><tr><th>الفئة</th><th>العنصر</th><th>مفعّل</th><th>الوزن %</th></tr><?php foreach(['low'=>'العاشرة فما دون','high'=>'الحادية عشرة وأعلى'] as $rk=>$rn)foreach($labels as $ek=>$en):?><tr><td><?=$rn?></td><td><?=$en?></td><td><input type="checkbox" name="e_<?=$rk?>_<?=$ek?>" <?=!empty($enabled[$rk][$ek])?'checked':''?>></td><td><input type="number" min="0" max="100" step="0.01" name="w_<?=$rk?>_<?=$ek?>" value="<?=htmlspecialchars((string)($weights[$rk][$ek]??0))?>"></td></tr><?php endforeach?></table></div></section>
<section class="card" id="appearance"><h2>المظهر والنصوص</h2><p>يمكن تعديل جميع النصوص الظاهرة للموظف من هنا.</p><div class="grid"><?php foreach($defaults as $k=>$v):?><div><label><?=htmlspecialchars($textLabels[$k]??$k)?></label><?php if($k==='tie_items'):?><textarea name="t_<?=$k?>" rows="7"><?=htmlspecialchars((string)($texts[$k]??$v))?></textarea><?php else:?><input name="t_<?=$k?>" value="<?=htmlspecialchars((string)($texts[$k]??$v))?>"><?php endif?></div><?php endforeach?></div></section><button style="width:100%;font-size:18px">حفظ جميع الإعدادات</button></form>
<section class="card" id="activity"><h2>النشاط</h2><div class="grid"><div>الزوار<div class="stat"><?=$stats['visitors']?></div></div><div>مرات العودة<div class="stat"><?=$stats['returns']?></div></div><div>عمليات البحث<div class="stat"><?=$stats['searches']?></div></div><div>الأحداث<div class="stat"><?=$stats['events']?></div></div></div><h3>آخر الزوار</h3><div class="weights"><table><tr><th>الرقم</th><th>الإنشاء</th><th>آخر تحديث</th><th>مرات العودة</th></tr><?php foreach($visitors as $v):?><tr><td><?=$v['visitor_code']?></td><td><?=$v['created_at']?></td><td><?=$v['updated_at']?></td><td><?=$v['return_count']?></td></tr><?php endforeach?></table></div></section><?php endif?></main></body></html>
